import { useState } from "react";
import useAge from "../hooks/useAge";
import maePhoto from "../assets/mae.jpg";
import styles from "./About.module.css";

const SKILLS = {
  Programming: [
    "Java",
    "Kotlin",
    "Python",
    "C++",
    "C#",
    "JavaScript",
    "VB.NET",
    "PHP",
    "Dart",
  ],
  MobileDevelopment: [
    "Android Studio",
    "Jetpack",
    "XML Layouts",
    "REST API Integration",
    "RFID Integration",
  ],
  Frameworks: ["React", "Flutter", "Laravel", "ASP.NET", "Qt"],
  Databases: ["MySQL", "PostgreSQL", "MongoDB"],
  DataEngineering: ["SQL", "Data Pipelines", "Data Processing"],
  CyberSecurity: [
    "Kali Linux",
    "Wireshark",
    "Cryptography Fundamentals",
    "Cisco Packet Tracer",
    "Network Configuration",
    "Bash",
    "Linux Command Line",
    "Shell Scripting",
  ],
  CloudDevOps: ["AWS", "GCP", "Git", "cPanel"],
  APIs: ["REST APIs", "RFID APIs", "JSON Handling", "Postman Testing"],
};

export default function About() {
  const age = useAge();

  // Track which categories are expanded
  const [expanded, setExpanded] = useState({});

  const toggleCategory = (category) => {
    setExpanded((prev) => ({ ...prev, [category]: !prev[category] }));
  };

  const handleDownload = () => {
    const a = document.createElement("a");
    a.href = "/Cruz_Jhustie-CV.pdf";
    a.download = "Cruz_Jhustie-CV.pdf";
    a.click();
  };

  return (
    <section className={styles.about} id="about">
      <div className={styles.label}>About Me</div>
      <h2 className={styles.title}>
        The person
        <br />
        behind the code
      </h2>

      <div className={styles.grid}>
        {/* Photo */}
        <div className={styles.imgWrap}>
          <div className={styles.imgFrame} />
          <img src={maePhoto} alt="Jhustie Mae Cruz" className={styles.photo} />
        </div>

        {/* Text */}
        <div className={styles.content}>
          <p>
            I am <strong>Jhustie Mae</strong>, a{" "}
            <strong>
              <span className={styles.age}>{age}</span> year old
            </strong>{" "}
            graduate (cum laude) based in Metro Manila. I have experience in
            mobile development, data engineering, cybersecurity, and API/RFID
            integrations.
          </p>
          <p>
            I previously interned at <strong>Lino</strong> and enjoy working on
            projects that challenge me to learn new technologies.
          </p>

          <div className={styles.tags}>
            {Object.entries(SKILLS).map(([category, skills]) => {
              const showCount = 4; // show first 4 by default
              const isExpanded = expanded[category];
              const displayedSkills = isExpanded
                ? skills
                : skills.slice(0, showCount);

              return (
                <div key={category} className={styles.skillCategory}>
                  <strong>{category}:</strong>{" "}
                  {displayedSkills.map((skill) => (
                    <span key={skill} className={styles.tag}>
                      {skill}
                    </span>
                  ))}
                  {skills.length > showCount && (
                    <button
                      className={styles.seeMoreBtn}
                      onClick={() => toggleCategory(category)}
                    >
                      {isExpanded ? "See Less" : "See More"}
                    </button>
                  )}
                </div>
              );
            })}
          </div>

          <button className={styles.btn} onClick={handleDownload}>
            Download Resume ↓
          </button>
        </div>
      </div>
    </section>
  );
}
